import React, { useState } from 'react';
import Home from './pages/Home';
import Login from './pages/Login';
import 'bootstrap/dist/css/bootstrap.min.css';

function App() {
  // 'page' state tharvel ki Home dakhvayche ki Login
  const [currentPage, setCurrentPage] = useState('home');

  const backgroundStyle = {
    backgroundImage: `linear-gradient(rgba(255, 255, 255, 0.7), rgba(255, 255, 255, 0.7)), url('https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?auto=format&fit=crop&q=80&w=2000')`,
    backgroundSize: 'cover',
    backgroundPosition: 'center',
    backgroundAttachment: 'fixed',
    minHeight: '100vh'
  };

  return (
    <div style={backgroundStyle}>
      {/* Navbar */}
      <nav className="navbar navbar-expand-lg navbar-dark px-4 shadow-sm py-2" style={{ backgroundColor: '#0056b3' }}>
        <div className="container-fluid">
          <span 
            className="navbar-brand fw-bold" 
            style={{ cursor: 'pointer' }} 
            onClick={() => setCurrentPage('home')}
          >
            APNI MANZIL
          </span>

          <div className="ms-auto">
            {currentPage === 'home' ? (
              <button 
                onClick={() => setCurrentPage('login')} 
                className="btn btn-success rounded-pill px-4 fw-bold shadow-sm"
              >
                Login
              </button>
            ) : (
              <button 
                onClick={() => setCurrentPage('home')} 
                className="btn btn-light rounded-pill px-4 fw-bold shadow-sm"
              >
                Back to Home
              </button>
            )}
          </div>
        </div>
      </nav>

      {/* Conditional Rendering: Page badalnyachi logic */}
      <main>
        {currentPage === 'home' ? <Home /> : <Login />}
      </main>

      <footer className="text-center py-4 text-muted small mt-auto">
        © 2026 Apni Manzil | Professional Logistics Solution
      </footer>
    </div>
  );
}

export default App;
